using System.IdentityModel.Tokens.Jwt;
using System.Security.Claims;
using System.Security.Cryptography;
using System.Text;
using Microsoft.Extensions.Configuration;
using Microsoft.IdentityModel.Tokens;
using YunTianYou.Domain.Entities;

namespace YunTianYou.Application.Services;

/// <summary>
/// JWT认证服务
/// </summary>
public class AuthService
{
    private readonly IConfiguration _configuration;
    private readonly UserService _userService;

    public AuthService(IConfiguration configuration, UserService userService)
    {
        _configuration = configuration;
        _userService = userService;
    }

    /// <summary>
    /// 用户注册
    /// </summary>
    public async Task<(User? User, string? Token, string? Error)> RegisterAsync(
        string username, string email, string password)
    {
        // 检查用户是否存在
        var existingUser = await _userService.GetByUsernameAsync(username);
        if (existingUser != null)
        {
            return (null, null, "用户名已存在");
        }

        var existingEmail = await _userService.GetByEmailAsync(email);
        if (existingEmail != null)
        {
            return (null, null, "邮箱已被注册");
        }

        // 创建用户
        var user = new User
        {
            Username = username,
            Email = email,
            PasswordHash = HashPassword(password),
            Role = "user",
            IsActive = true
        };

        var createdUser = await _userService.CreateAsync(user);
        var token = GenerateJwtToken(createdUser);

        return (createdUser, token, null);
    }

    /// <summary>
    /// 用户登录
    /// </summary>
    public async Task<(User? User, string? Token, string? Error)> LoginAsync(
        string username, string password)
    {
        var user = await _userService.GetByUsernameAsync(username);
        if (user == null)
        {
            return (null, null, "用户名或密码错误");
        }

        if (!user.IsActive)
        {
            return (null, null, "账户已被禁用");
        }

        if (!VerifyPassword(password, user.PasswordHash))
        {
            return (null, null, "用户名或密码错误");
        }

        var token = GenerateJwtToken(user);
        return (user, token, null);
    }

    /// <summary>
    /// 生成JWT Token
    /// </summary>
    private string GenerateJwtToken(User user)
    {
        var jwtKey = _configuration["Jwt:Key"] ?? "YunTianYou_Secret_Key_2026_Very_Long_Key_For_Security";
        var jwtIssuer = _configuration["Jwt:Issuer"] ?? "YunTianYou";
        var jwtAudience = _configuration["Jwt:Audience"] ?? "YunTianYou";
        var expirationHours = int.Parse(_configuration["Jwt:ExpirationHours"] ?? "24");

        var securityKey = new SymmetricSecurityKey(Encoding.UTF8.GetBytes(jwtKey));
        var credentials = new SigningCredentials(securityKey, SecurityAlgorithms.HmacSha256);

        var claims = new[]
        {
            new Claim(JwtRegisteredClaimNames.Sub, user.Id.ToString()),
            new Claim(JwtRegisteredClaimNames.UniqueName, user.Username),
            new Claim(JwtRegisteredClaimNames.Email, user.Email),
            new Claim(ClaimTypes.Role, user.Role ?? "user"),
            new Claim(JwtRegisteredClaimNames.Jti, Guid.NewGuid().ToString())
        };

        var token = new JwtSecurityToken(
            issuer: jwtIssuer,
            audience: jwtAudience,
            claims: claims,
            expires: DateTime.UtcNow.AddHours(expirationHours),
            signingCredentials: credentials
        );

        return new JwtSecurityTokenHandler().WriteToken(token);
    }

    /// <summary>
    /// 密码哈希
    /// </summary>
    private string HashPassword(string password)
    {
        using var sha256 = SHA256.Create();
        var salt = "YunTianYou_Salt_2026";
        var saltedPassword = password + salt;
        var bytes = sha256.ComputeHash(Encoding.UTF8.GetBytes(saltedPassword));
        return Convert.ToBase64String(bytes);
    }

    /// <summary>
    /// 验证密码
    /// </summary>
    private bool VerifyPassword(string password, string hash)
    {
        return HashPassword(password) == hash;
    }

    /// <summary>
    /// 验证JWT Token
    /// </summary>
    public ClaimsPrincipal? ValidateToken(string token)
    {
        try
        {
            var jwtKey = _configuration["Jwt:Key"] ?? "YunTianYou_Secret_Key_2026_Very_Long_Key_For_Security";
            var jwtIssuer = _configuration["Jwt:Issuer"] ?? "YunTianYou";
            var jwtAudience = _configuration["Jwt:Audience"] ?? "YunTianYou";

            var tokenHandler = new JwtSecurityTokenHandler();
            var key = Encoding.UTF8.GetBytes(jwtKey);

            var validationParameters = new TokenValidationParameters
            {
                ValidateIssuer = true,
                ValidateAudience = true,
                ValidateLifetime = true,
                ValidateIssuerSigningKey = true,
                ValidIssuer = jwtIssuer,
                ValidAudience = jwtAudience,
                IssuerSigningKey = new SymmetricSecurityKey(key)
            };

            var principal = tokenHandler.ValidateToken(token, validationParameters, out _);
            return principal;
        }
        catch
        {
            return null;
        }
    }
}

using YunTianYou.Domain.Entities;

namespace YunTianYou.Application.Services;

/// <summary>
/// 工作流服务 - 流程引擎核心
/// </summary>
public class WorkflowService
{
    private readonly List<Workflow> _workflows = new();
    private readonly List<WorkflowInstance> _instances = new();
    private readonly List<WorkflowApproval> _approvals = new();

    /// <summary>
    /// 创建工作流定义
    /// </summary>
    public async Task<Workflow> CreateWorkflowAsync(
        string name, string description, string definition, Guid createdByUserId)
    {
        var workflow = new Workflow
        {
            Id = Guid.NewGuid(),
            Name = name,
            Description = description,
            Definition = definition,
            IsActive = true,
            Version = 1,
            CreatedByUserId = createdByUserId,
            CreatedAt = DateTime.UtcNow
        };

        _workflows.Add(workflow);
        return await Task.FromResult(workflow);
    }

    /// <summary>
    /// 启动工作流实例
    /// </summary>
    public async Task<WorkflowInstance> StartInstanceAsync(
        Guid workflowId, string data, Guid initiatedByUserId)
    {
        var workflow = _workflows.FirstOrDefault(w => w.Id == workflowId);
        if (workflow == null)
        {
            throw new ArgumentException("工作流不存在");
        }

        var instance = new WorkflowInstance
        {
            Id = Guid.NewGuid(),
            WorkflowId = workflowId,
            Status = "running",
            CurrentNode = "start",
            Data = data,
            InitiatedByUserId = initiatedByUserId,
            StartedAt = DateTime.UtcNow,
            CreatedAt = DateTime.UtcNow
        };

        _instances.Add(instance);

        // 触发开始节点
        await ProcessNodeAsync(instance, "start");

        return instance;
    }

    /// <summary>
    /// 处理流程节点
    /// </summary>
    private async Task ProcessNodeAsync(WorkflowInstance instance, string nodeName)
    {
        instance.CurrentNode = nodeName;

        // 根据节点类型执行不同逻辑
        switch (nodeName)
        {
            case "start":
                // 开始节点，自动流转到下一个节点
                await MoveToNextNodeAsync(instance, "submit");
                break;

            case "submit":
                // 提交节点，等待审批
                instance.Status = "pending_approval";
                break;

            case "approve":
                // 审批节点
                instance.Status = "approved";
                await MoveToNextNodeAsync(instance, "end");
                break;

            case "reject":
                // 拒绝节点
                instance.Status = "rejected";
                await MoveToNextNodeAsync(instance, "end");
                break;

            case "end":
                // 结束节点
                instance.Status = "completed";
                instance.CompletedAt = DateTime.UtcNow;
                break;
        }
    }

    /// <summary>
    /// 移动到下一个节点
    /// </summary>
    private async Task MoveToNextNodeAsync(WorkflowInstance instance, string nextNode)
    {
        await ProcessNodeAsync(instance, nextNode);
    }

    /// <summary>
    /// 审批操作
    /// </summary>
    public async Task<WorkflowApproval> ApproveAsync(
        Guid instanceId, Guid approvedByUserId, string action, string? comment)
    {
        var instance = _instances.FirstOrDefault(i => i.Id == instanceId);
        if (instance == null)
        {
            throw new ArgumentException("工作流实例不存在");
        }

        var approval = new WorkflowApproval
        {
            Id = Guid.NewGuid(),
            WorkflowInstanceId = instanceId,
            NodeName = instance.CurrentNode,
            ApprovedByUserId = approvedByUserId,
            Action = action,
            Comment = comment,
            ActionAt = DateTime.UtcNow,
            CreatedAt = DateTime.UtcNow
        };

        _approvals.Add(approval);

        // 根据审批动作流转
        if (action == "approved")
        {
            await MoveToNextNodeAsync(instance, "approve");
        }
        else if (action == "rejected")
        {
            await MoveToNextNodeAsync(instance, "reject");
        }

        return approval;
    }

    /// <summary>
    /// 获取工作流列表
    /// </summary>
    public async Task<List<Workflow>> GetWorkflowsAsync()
    {
        return await Task.FromResult(_workflows.ToList());
    }

    /// <summary>
    /// 获取工作流实例
    /// </summary>
    public async Task<WorkflowInstance?> GetInstanceAsync(Guid instanceId)
    {
        return await Task.FromResult(_instances.FirstOrDefault(i => i.Id == instanceId));
    }

    /// <summary>
    /// 获取用户的待办任务
    /// </summary>
    public async Task<List<WorkflowInstance>> GetPendingTasksAsync(Guid userId)
    {
        return await Task.FromResult(
            _instances.Where(i => i.Status == "pending_approval").ToList());
    }
}

using System.Text;
using YunTianYou.Domain.Entities;

namespace YunTianYou.Application.Services;

/// <summary>
/// 代码生成器服务 - 从数据模型生成代码
/// </summary>
public class CodeGeneratorService
{
    private readonly List<DataModel> _dataModels = new();
    private readonly List<GeneratedCode> _generatedCodes = new();

    /// <summary>
    /// 创建数据模型
    /// </summary>
    public async Task<DataModel> CreateDataModelAsync(
        string name, string description, string schema, Guid createdByUserId)
    {
        var model = new DataModel
        {
            Id = Guid.NewGuid(),
            Name = name,
            Description = description,
            Schema = schema,
            TableName = ToSnakeCase(name),
            IsPublished = false,
            CreatedByUserId = createdByUserId,
            CreatedAt = DateTime.UtcNow
        };

        _dataModels.Add(model);
        return await Task.FromResult(model);
    }

    /// <summary>
    /// 生成所有代码
    /// </summary>
    public async Task<List<GeneratedCode>> GenerateAllCodeAsync(Guid dataModelId)
    {
        var model = _dataModels.FirstOrDefault(m => m.Id == dataModelId);
        if (model == null)
        {
            throw new ArgumentException("数据模型不存在");
        }

        var codes = new List<GeneratedCode>
        {
            await GenerateEntityAsync(model),
            await GenerateServiceAsync(model),
            await GenerateControllerAsync(model),
            await GenerateReactComponentAsync(model),
            await GenerateSqlAsync(model)
        };

        _generatedCodes.AddRange(codes);
        model.IsPublished = true;

        return codes;
    }

    /// <summary>
    /// 生成实体类代码
    /// </summary>
    private async Task<GeneratedCode> GenerateEntityAsync(DataModel model)
    {
        var sb = new StringBuilder();
        sb.AppendLine("using System.ComponentModel.DataAnnotations;");
        sb.AppendLine("using System.ComponentModel.DataAnnotations.Schema;");
        sb.AppendLine();
        sb.AppendLine($"namespace YunTianYou.Domain.Entities;");
        sb.AppendLine();
        sb.AppendLine($"/// <summary>");
        sb.AppendLine($"/// {model.Description ?? model.Name}实体");
        sb.AppendLine($"/// </summary>");
        sb.AppendLine($"[Table(\"{model.TableName}\")]");
