using Microsoft.AspNetCore.Mvc;
using YunTianYou.Application.DTOs;
using YunTianYou.Application.Services;

namespace YunTianYou.Api.Controllers;

/// <summary>
/// 认证控制器 - 登录注册
/// </summary>
[ApiController]
[Route("api/[controller]")]
public class AuthController : ControllerBase
{
    private readonly AuthService _authService;

    public AuthController(AuthService authService)
    {
        _authService = authService;
    }

    /// <summary>
    /// 用户注册
    /// </summary>
    [HttpPost("register")]
    public async Task<ActionResult<AuthResponse>> Register([FromBody] RegisterRequest request)
    {
        var (user, token, error) = await _authService.RegisterAsync(
            request.Username, request.Email, request.Password);

        if (error != null || user == null || token == null)
        {
            return BadRequest(new { error = error ?? "注册失败" });
        }

        return Ok(new AuthResponse
        {
            UserId = user.Id,
            Username = user.Username,
            Email = user.Email,
            Token = token,
            Role = user.Role ?? "user"
        });
    }

    /// <summary>
    /// 用户登录
    /// </summary>
    [HttpPost("login")]
    public async Task<ActionResult<AuthResponse>> Login([FromBody] LoginRequest request)
    {
        var (user, token, error) = await _authService.LoginAsync(
            request.Username, request.Password);

        if (error != null || user == null || token == null)
        {
            return Unauthorized(new { error = error ?? "登录失败" });
        }

        return Ok(new AuthResponse
        {
            UserId = user.Id,
            Username = user.Username,
            Email = user.Email,
            Token = token,
            Role = user.Role ?? "user"
        });
    }

    /// <summary>
    /// 验证Token
    /// </summary>
    [HttpPost("validate")]
    public ActionResult ValidateToken([FromBody] ValidateTokenRequest request)
    {
        var principal = _authService.ValidateToken(request.Token);
        if (principal == null)
        {
            return Unauthorized(new { error = "Token无效" });
        }

        return Ok(new { valid = true, username = principal.Identity?.Name });
    }
}

// DTOs
public class RegisterRequest
{
    public string Username { get; set; } = string.Empty;
    public string Email { get; set; } = string.Empty;
    public string Password { get; set; } = string.Empty;
}

public class LoginRequest
{
    public string Username { get; set; } = string.Empty;
    public string Password { get; set; } = string.Empty;
}

public class ValidateTokenRequest
{
    public string Token { get; set; } = string.Empty;
}

public class AuthResponse
{
    public Guid UserId { get; set; }
    public string Username { get; set; } = string.Empty;
    public string Email { get; set; } = string.Empty;
    public string Token { get; set; } = string.Empty;
    public string Role { get; set; } = string.Empty;
}

using Microsoft.AspNetCore.Mvc;
using YunTianYou.Application.Services;

namespace YunTianYou.Api.Controllers;

/// <summary>
/// 工作流控制器 - 流程管理
/// </summary>
[ApiController]
[Route("api/[controller]")]
public class WorkflowsController : ControllerBase
{
    private readonly WorkflowService _workflowService;

    public WorkflowsController(WorkflowService workflowService)
    {
        _workflowService = workflowService;
    }

    /// <summary>
    /// 获取工作流列表
    /// </summary>
    [HttpGet]
    public async Task<ActionResult> GetAll()
    {
        var workflows = await _workflowService.GetWorkflowsAsync();
        return Ok(workflows);
    }

    /// <summary>
    /// 创建工作流
    /// </summary>
    [HttpPost]
    public async Task<ActionResult> Create([FromBody] CreateWorkflowRequest request)
    {
        var workflow = await _workflowService.CreateWorkflowAsync(
            request.Name, request.Description ?? "", request.Definition, request.CreatedByUserId);
        return Ok(workflow);
    }

    /// <summary>
    /// 启动工作流实例
    /// </summary>
    [HttpPost("{id}/start")]
    public async Task<ActionResult> StartInstance(Guid id, [FromBody] StartWorkflowRequest request)
    {
        try
        {
            var instance = await _workflowService.StartInstanceAsync(
                id, request.Data, request.InitiatedByUserId);
            return Ok(instance);
        }
        catch (ArgumentException ex)
        {
            return NotFound(new { error = ex.Message });
        }
    }

    /// <summary>
    /// 获取工作流实例
    /// </summary>
    [HttpGet("instances/{instanceId}")]
    public async Task<ActionResult> GetInstance(Guid instanceId)
    {
        var instance = await _workflowService.GetInstanceAsync(instanceId);
        if (instance == null)
        {
            return NotFound();
        }
        return Ok(instance);
    }

    /// <summary>
    /// 审批操作
    /// </summary>
    [HttpPost("instances/{instanceId}/approve")]
    public async Task<ActionResult> Approve(Guid instanceId, [FromBody] ApproveRequest request)
    {
        try
        {
            var approval = await _workflowService.ApproveAsync(
                instanceId, request.ApprovedByUserId, request.Action, request.Comment);
            return Ok(approval);
        }
        catch (ArgumentException ex)
        {
            return NotFound(new { error = ex.Message });
        }
    }

    /// <summary>
    /// 获取待办任务
    /// </summary>
    [HttpGet("pending/{userId}")]
    public async Task<ActionResult> GetPendingTasks(Guid userId)
    {
        var tasks = await _workflowService.GetPendingTasksAsync(userId);
        return Ok(tasks);
    }
}

